// Добавляем дельту яркости к пикселям (0-255) с насыщением
std::array<unsigned char, 4> add_brightness(
    std::array<unsigned char, 4> pixels, int delta)
{
    std::array<unsigned char, 4> result;
    for (int i = 0; i < 4; ++i)
        result[i] = std::saturating_cast<unsigned char>(
            (int)pixels[i] + delta);
    return result;
}

int main() {
    auto pixels = std::array<unsigned char, 4>{200, 100, 50, 240};
    auto bright = add_brightness(pixels, 80);
    for (auto p : bright)
        std::print("{} ", (int)p);
    std::println("");
}

