challenge.referenceSolution:
```cpp
#include <numeric>
#include <cstdint>
#include <print>

int16_t audio_mix(int16_t a, int16_t b) {
    return std::saturating_cast<int16_t>((int)a + (int)b);
}

int main() {
    std::println("{}", audio_mix(30000, 30000));   // насыщение до 32767
    std::println("{}", audio_mix(-30000, -30000)); // насыщение до -32768
    std::println("{}", audio_mix(100, 200));       // нет насыщения: 300
}
```

